import{_ as o,o as e,c as t,a0 as n}from"./chunks/framework.jwovEGr5.js";const l="/assets/Image-(5).CQdh2Df-.png",i="/assets/Image-(6).Ur2EWrVH.png",r="/assets/Image-(7).QgAOxK_a.png",f=JSON.parse('{"title":"7_cuda_dnn","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/study/멀티코어및GPU프로그래밍/7_cuda_dnn.md","filePath":"outta-space/study/멀티코어및GPU프로그래밍/7_cuda_dnn.md"}'),u={name:"outta-space/study/멀티코어및GPU프로그래밍/7_cuda_dnn.md"};function c(s,a,d,m,_,p){return e(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="_7-cuda-dnn" tabindex="-1">7_cuda_dnn <a class="header-anchor" href="#_7-cuda-dnn" aria-label="Permalink to &quot;7_cuda_dnn&quot;">​</a></h1><h3 id="deep-neural-network" tabindex="-1">Deep neural network <a class="header-anchor" href="#deep-neural-network" aria-label="Permalink to &quot;Deep neural network&quot;">​</a></h3><ul><li>input이 들어오면 weight를 곱하고 bias를 더해 output를 만들어내는 unit으로 이루어진 거대한 신경망.</li><li>각 layer는 종류에 따라 fully connected, sparsely connected layer로 나뉠 수 있다.</li></ul><h3 id="_2d-convolution" tabindex="-1">2D Convolution <a class="header-anchor" href="#_2d-convolution" aria-label="Permalink to &quot;2D Convolution&quot;">​</a></h3><p><img src="'+l+'" alt="Image.png"></p><ul><li>각 image는 pixel들을 특정 값으로 변환한 형태로 나타낼 수 있다.</li><li>이미지에 filter mask (혹은 filter, kernel)를 convolution 연산을 하면 이미지의 특정한 &#39;특징&#39;을 뽑아낼 수 있다.</li><li>DNN layer에서는 N개의 filter를 사용해 N개의 feature map(response map)를 뽑아내는 형식이다.</li></ul><h3 id="activation-function" tabindex="-1">Activation function <a class="header-anchor" href="#activation-function" aria-label="Permalink to &quot;Activation function&quot;">​</a></h3><ul><li>비선형성을 추가하기 위해 layer 사이에 들어가는 함수이다.</li><li>ReLU, sigmoid 등이 있다.</li></ul><h3 id="convolution-layer" tabindex="-1">Convolution layer <a class="header-anchor" href="#convolution-layer" aria-label="Permalink to &quot;Convolution layer&quot;">​</a></h3><ul><li>Convolution layer의 계산 과정을 코드로 러프하게 나타내면 다음과 같다.</li></ul><p><img src="'+i+'" alt="Image.png"></p><ul><li>즉 convolution은 7중 for문으로 이루어져 있는 것!</li><li>병렬화는 작은 수준의 병렬화만 가능한 n,m,h,w 쪽보다 c,p,q 쪽을 병렬화하는 것이 효율이 좋다. (왜지)</li><li>또한 convolution 중간에 생기는 중복된 원소의 사용은 역시 shared memory의 사용으로 해결한다.</li></ul><h3 id="im2col" tabindex="-1">im2col <a class="header-anchor" href="#im2col" aria-label="Permalink to &quot;im2col&quot;">​</a></h3><ul><li>아무래도 GPU는 matmul에 특화되어 있다. Convolution 연산을 이것으로 바꾸는 방법은 없을까?</li><li><strong>im2col은</strong> Convolution 연산을 matmul로 간편하게 만들어 주는 단계이다.</li></ul><p><img src="'+r+'" alt="Image.png"></p><ul><li>weight와 input을 펼쳐 matrix를 만들고, 이를 matmul해 output matrix를 만들어내는 방식이다.</li><li>이외에도 convolution을 수행하는 다른 방법으로는 FFT-based convolution, <a href="craftdocs://open?blockId=58B8B8FF-8B37-4DF6-862A-A4DB0D8C4BDA&amp;spaceId=13dc16b5-1640-e515-ca68-8cd96caa1139" target="_blank" rel="noreferrer">Winograd transform</a> 등이 있다.</li></ul>',16)])])}const g=o(u,[["render",c]]);export{f as __pageData,g as default};
